{
  "operationName": "Signup",
  "query": "mutation Signup($username: String!, $email: String!, $password: String!) { signup(username: $username, email: $email, password: $password) { success message user { id username email created_at } } }",
  "variables": {
    "username": "testuser",
    "email": "testuser@example.com",
    "password": "Password123"
  }
}

{
  "operationName": "Login",
  "query": "mutation Login($usernameOrEmail: String!, $password: String!) { login(usernameOrEmail: $usernameOrEmail, password: $password) { success message token user { id username email } } }",
  "variables": {
    "usernameOrEmail": "renan",
    "password": "Password123"
  }
}

{
  "operationName": "GetAllEmployees",
  "query": "query GetAllEmployees { getAllEmployees { success message employees { id first_name last_name email designation department salary gender date_of_joining employee_photo } } }",
  "variables": {}
}

{
  "operationName": "AddEmployee",
  "query": "mutation AddEmployee($input: EmployeeInput!) { addEmployee(input: $input) { success message employee { id first_name last_name email designation department salary gender date_of_joining employee_photo } } }",
  "variables": {
    "input": {
      "first_name": "Renan",
      "last_name": "Makoto",
      "email": "renan.makoto@example.com",
      "gender": "Male",
      "designation": "Developer",
      "salary": 5200,
      "date_of_joining": "2025-01-10T00:00:00.000Z",
      "department": "Engineering",
      "employee_photo": null
    }
  }
}

{
  "operationName": "GetEmployeeById",
  "query": "query GetEmployeeById($eid: ID!) { getEmployeeById(eid: $eid) { success message employee { id first_name last_name email designation department } } }",
  "variables": {
    "eid": "6974d405c31d011b1c646dc6"
  }
}

{
  "operationName": "UpdateEmployeeById",
  "query": "mutation UpdateEmployeeById($eid: ID!, $input: EmployeeUpdateInput!) { updateEmployeeById(eid: $eid, input: $input) { success message employee { id first_name last_name email designation department salary gender date_of_joining employee_photo } } }",
  "variables": {
    "eid": "6974d405c31d011b1c646dc6",
    "input": {
      "designation": "DevOps - UPDATED",
      "salary": 7500
    }
  }
}

{
  "operationName": "SearchEmployees",
  "query": "query SearchEmployees($designation: String, $department: String) { searchEmployees(designation: $designation, department: $department) { success message employees { id first_name last_name email designation department } } }",
  "variables": {
    "designation": "DevOps - UPDATED"
  }
}
